```jsx
function Avatar({ src, alt, name, size = "md", ...rest }) {
  const sizeClass = size !== "md" ? `avatar-${size}` : "";
  const initials = name
    ? name.split(" ").map(w => w[0]).slice(0, 2).join("").toUpperCase()
    : null;

  return (
    <span className={`avatar ${sizeClass}`} {...rest}>
      {src ? <img src={src} alt={alt ?? name ?? ""} /> : initials}
    </span>
  );
}
```

