```

**Bruk:**
```jsx
<section>
  <FeatureRow
    eyebrow="Subscriptions"
    title="Monthly revenue from your most dedicated fans"
    description="With custom tiers, perks, and pricing."
    cta={{ label: "Get started", href: "/start" }}
    preview={<DashboardPreview />}
  />
  <FeatureRow
    reverse
    eyebrow="Analytics"
